patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..5fe41e0fb870 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4510,8 +4510,18 @@ static Instruction *foldICmpOrXX(ICmpInst &I, const SimplifyQuery &Q,
 static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
                                   InstCombinerImpl &IC) {
   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
-  // Normalize xor operand as operand 0.
   CmpInst::Predicate Pred = I.getPredicate();
+  // New pattern: icmp pred (~A ^ B), ~C -> icmp swapped pred (A ^ B), C
+  {
+    Value *A2, *B2, *C2;
+    if (match(Op0, m_c_Xor(m_c_Xor(m_Value(A2), m_AllOnes()), m_Value(B2))) &&
+        match(Op1, m_c_Xor(m_Value(C2), m_AllOnes()))) {
+      Value *NewXor = IC.Builder.CreateXor(A2, B2);
+      Pred = ICmpInst::getSwappedPredicate(Pred);
+      return new ICmpInst(Pred, NewXor, C2);
+    }
+  }
+  // Normalize xor operand as operand 0.
   if (match(Op1, m_c_Xor(m_Specific(Op0), m_Value()))) {
     std::swap(Op0, Op1);
     Pred = ICmpInst::getSwappedPredicate(Pred);
@@ -4528,6 +4538,23 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // (X ^ Y) eq/ne X --> Y eq/ne 0
+  if (ICmpInst::isEquality(Pred)) {
+    Constant *Zero = Constant::getNullValue(Op1->getType());
+    return new ICmpInst(Pred, A, Zero);
+  }
+
+  // If X = ~C, then (X ^ Y) Pred X --> (C ^ Y) Pred' C where Pred' is swapped.
+  Value *C;
+  if (match(Op1, m_c_Xor(m_Value(C), m_AllOnes()))) {
+    // Op1 = C ^ -1 (i.e., ~C)
+    // Op0 = Op1 ^ A = ~C ^ A
+    // Transform to (C ^ A) Pred' C
+    Value *NewXor = IC.Builder.CreateXor(C, A);
+    Pred = ICmpInst::getSwappedPredicate(Pred);
+    return new ICmpInst(Pred, NewXor, C);
+  }
+
   return nullptr;
 }

